SELECT count(*) FROM name, aka_name, cast_info, title, movie_info, role_type, movie_companies WHERE aka_name.person_id = name.id AND cast_info.person_id = name.id AND cast_info.movie_id = title.id AND movie_info.movie_id = title.id AND cast_info.role_id = role_type.id AND movie_companies.movie_id = title.id;